import { useState, useEffect } from 'react'
import ReviewCard from '../components/ReviewCard'
import ReviewFilters from '../components/ReviewFilters'
import ReviewStats from '../components/ReviewStats'
import { fetchReviews, approveReview, rejectReview, resetReview } from '../services/api'

const Dashboard = () => {
  const [reviews, setReviews] = useState([])
  const [loading, setLoading] = useState(true)
  const [filters, setFilters] = useState({
    rating: '',
    category: '',
    listing: '',
    status: '',
    startDate: '',
    endDate: '',
    sortBy: 'submittedAt',
    sortOrder: 'desc'
  })
  const [pagination, setPagination] = useState({
    currentPage: 1,
    totalPages: 1,
    totalItems: 0,
    itemsPerPage: 20
  })

  useEffect(() => {
    loadReviews()
  }, [filters, pagination.currentPage])

  const loadReviews = async () => {
    try {
      setLoading(true)
      const response = await fetchReviews(filters, pagination.currentPage)
      setReviews(response.data)
      setPagination(response.pagination)
    } catch (error) {
      console.error('Error loading reviews:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleApproveReview = async (reviewId) => {
    try {
      await approveReview(reviewId)
      await loadReviews() // Reload to get updated data
    } catch (error) {
      console.error('Error approving review:', error)
    }
  }

  const handleRejectReview = async (reviewId) => {
    try {
      await rejectReview(reviewId)
      await loadReviews() // Reload to get updated data
    } catch (error) {
      console.error('Error rejecting review:', error)
    }
  }

  const handleResetReview = async (reviewId) => {
    try {
      await resetReview(reviewId)
      await loadReviews() // Reload to get updated data
    } catch (error) {
      console.error('Error resetting review:', error)
    }
  }

  const handleFilterChange = (newFilters) => {
    setFilters(newFilters)
    setPagination(prev => ({ ...prev, currentPage: 1 }))
  }

  const handlePageChange = (page) => {
    setPagination(prev => ({ ...prev, currentPage: page }))
  }

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Reviews Dashboard</h1>
          <p className="text-gray-600 mt-1">Manage and monitor guest reviews across all properties</p>
        </div>
        <button 
          onClick={() => loadReviews()}
          className="btn btn-primary"
        >
          🔄 Refresh
        </button>
      </div>

      {/* Stats Cards */}
      <ReviewStats reviews={reviews} />

      {/* Filters */}
      <ReviewFilters 
        filters={filters} 
        onFilterChange={handleFilterChange} 
      />

      {/* Reviews List */}
      <div className="card">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-semibold text-gray-900">
            Reviews ({pagination.totalItems})
          </h2>
          <div className="flex items-center gap-2 text-sm text-gray-500">
            <span>Page {pagination.currentPage} of {pagination.totalPages}</span>
          </div>
        </div>

        {loading ? (
          <div className="flex justify-center items-center py-12">
            <div className="spinner"></div>
          </div>
        ) : reviews.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-gray-500">No reviews found with the current filters.</p>
          </div>
        ) : (
          <>
            <div className="space-y-4">
              {reviews.map((review) => (
                <ReviewCard
                  key={review.id}
                  review={review}
                  onApprove={() => handleApproveReview(review.id)}
                  onReject={() => handleRejectReview(review.id)}
                  onReset={() => handleResetReview(review.id)}
                />
              ))}
            </div>

            {/* Pagination */}
            {pagination.totalPages > 1 && (
              <div className="flex justify-center items-center gap-2 mt-6 pt-6 border-t border-gray-200">
                <button
                  onClick={() => handlePageChange(pagination.currentPage - 1)}
                  disabled={pagination.currentPage === 1}
                  className="btn btn-secondary disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Previous
                </button>

                {Array.from({ length: pagination.totalPages }, (_, i) => i + 1).map((page) => (
                  <button
                    key={page}
                    onClick={() => handlePageChange(page)}
                    className={`btn ${page === pagination.currentPage ? 'btn-primary' : 'btn-secondary'}`}
                  >
                    {page}
                  </button>
                ))}

                <button
                  onClick={() => handlePageChange(pagination.currentPage + 1)}
                  disabled={pagination.currentPage === pagination.totalPages}
                  className="btn btn-secondary disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Next
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  )
}

export default Dashboard
